"use strict";let util;layui.use(["laypage","util"],function(){util=layui.util});function getData(c,a,b){$.ajax({url:"/re/blog/listBlogPageByType",data:{type:b,page:c,count:a},method:"GET",dataType:"json",success:function(d){if(d.request==="success"&&d.status===200){renderData(d.data)}}})}function renderData(a){let lis=[];for(let i=0;i<a.length;i++){let item='<div class="articles">            <article class="article mb10 p10">                <header class="article-header mb10">                    <span class="article-label f12 mr5">'+a[i].type+'                       <i class="label-arrow"></i>                    </span>                    <span class="article-title f14">'+a[i].title+'</span>                </header>                <section class="article-detail flex">                    <div class="mr10 article-thumb cursor-pointer">                        <img src=\''+a[i].coverImage+"'                             alt='"+a[i].title+"'                             title='"+a[i].title+"'/>                    </div>                    <div class=\"article-summary flex flex-direction-column flex-justify-content-space-between\">                        <a href='/re/article/"+a[i].id+"'>"+a[i].summary+'                        </a>                        <div class="article-info">                            <a href="#">                               <i class="fa fa-user pr5" aria-hidden="true"></i>                               <span style=\'color: #00A67C;\'>'+a[i].author+'</span>                            </a>                            <a href="#">                               <i class="fa fa-clock-o" aria-hidden="true"></i>                               <span>'+util.toDateString(a[i].modifyTime,"yyyy-MM-dd")+'</span>                            </a>                            <a href="#">                               <i class="fa fa-eye" aria-hidden="true"></i>                               <span>'+a[i].view+'浏览</span>                            </a>                            <a href="#">                               <i class="fa fa-comment" aria-hidden="true"></i>                               <span>'+a[i].comment+"评论</span>                            </a>                        </div>                    </div>                </section>            </article>        </div>";lis.push(item);$(".articles").html(lis.join(""))}};